#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
    string filename, word;
    cout << "Enter the filename: ";
    cin >> filename;
    cout << "Enter the word to search for: ";
    cin >> word;

    ifstream file(filename);
    if (!file) {
        cerr << "Error opening file: " << filename << endl;
        return 1;
    }

    string line;
    int count = 0;
    while (getline(file, line)) {
        count += count(line, word);
    }

    file.close();

    cout << "The word '" << word << "' appears " << count << " times in the file " << filename << endl;

    return 0;
}

int count(string str, string word) {
    size_t pos = str.find(word);
    while (pos != string::npos) {
        pos = str.find(word, pos + 1);
        count++;
    }
    return count;
}
